/*
=====================================================================
 Design System: Pediatric Endocrinology Clinic
 Based on provided palette, typography, and the reference hero/header
=====================================================================
*/

:root {
  /* Color Palette */
  --color-primary-800: #1f3c8e; /* dark header/top bar */
  --color-primary-700: #2458c6; /* primary CTA */
  --color-primary-600: #2f5ecf; /* hover and accents */

  --color-secondary-500: #6f92d8;
  --color-secondary-300: #b7d5f5;

  --color-neutral-0: #ffffff;
  --color-neutral-25: #f5f7fa;
  --color-neutral-800: #333333;
  --color-neutral-500: #6b7280;
  --color-neutral-border: #e0e4ec;

  --color-success: #2e7d32;
  --color-error: #c62828;
  --color-warning: #ed6c02;
  --color-info: #0288d1;

  /* Typography */
  --font-heading: "DM Sans", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --fs-h1: 36px;
  --fs-h2: 28px;
  --fs-h3: 22px;
  --fs-body: 16px;
  --fs-small: 13px;

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* Spacing Scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --layout-max-width: 1200px;
  --header-height-desktop: 96px;
  --top-bar-height: 40px;
  --border-radius-card: 8px;
  --border-radius-pill: 999px;

  /* Shadows */
  --shadow-soft: 0 8px 20px rgba(15, 23, 42, 0.08);
}

/* Global Reset & Base Styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-25);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

ul,
ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

p {
  margin-top: 0;
  margin-bottom: var(--space-3);
}

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

/* Utility classes */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 24px;
  border-radius: var(--border-radius-pill);
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: var(--fw-semibold);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  border: none;
  cursor: pointer;
  transition: background-color 0.2s ease, box-shadow 0.2s ease, transform 0.1s ease;
  white-space: nowrap;
}

.btn-primary {
  background: var(--color-primary-700);
  color: var(--color-neutral-0);
  box-shadow: var(--shadow-soft);
}

.btn-primary:hover,
.btn-primary:focus {
  background: var(--color-primary-600);
  transform: translateY(-1px);
}

.btn-primary:active {
  transform: translateY(0);
  box-shadow: none;
}

/* Header Layout */

.site-header {
  background-color: var(--color-neutral-0);
  box-shadow: 0 1px 0 rgba(148, 163, 184, 0.4);
}

/* Top bar */

.top-bar {
  background-color: var(--color-primary-800);
  color: var(--color-neutral-0);
  font-size: var(--fs-small);
}

.top-bar-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: var(--top-bar-height);
}

.top-bar-left {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.top-item {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
}

.top-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.15);
  font-size: 11px;
}

.top-link {
  color: var(--color-neutral-0);
  text-decoration: none;
}

.top-link:hover,
.top-link:focus {
  text-decoration: underline;
}

.top-text {
  opacity: 0.9;
}

.top-bar-right {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.social-icon {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.15);
  position: relative;
}

.social-icon::before {
  content: "";
  position: absolute;
  inset: 6px;
  border-radius: 50%;
  background-color: var(--color-neutral-0);
  opacity: 0.75;
}

/* Main header */

.header-main {
  background-color: var(--color-neutral-0);
}

.header-main-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: var(--header-height-desktop);
  gap: var(--space-4);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-3) 0;
}

.brand-mark {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-800);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}

.brand-mark-face {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-800);
  position: absolute;
  top: 26px;
  background-color: var(--color-neutral-0);
}

.brand-mark-face--left {
  left: 13px;
}

.brand-mark-face--right {
  right: 13px;
}

.brand-text {
  display: flex;
  flex-direction: column;
}

.brand-title {
  font-family: var(--font-heading);
  font-weight: var(--fw-bold);
  font-size: 22px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-primary-800);
}

.brand-subtitle {
  font-size: 14px;
  font-weight: var(--fw-semibold);
  color: var(--color-neutral-800);
}

/* Main Navigation */

.main-nav {
  margin-left: auto;
}

.main-nav-list {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.main-nav-link {
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: var(--fw-medium);
  color: var(--color-neutral-800);
  padding: 4px 0;
  position: relative;
  white-space: nowrap;
}

.main-nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: -6px;
  height: 2px;
  border-radius: 999px;
  background-color: transparent;
  transition: background-color 0.2s ease;
}

.main-nav-link:hover,
.main-nav-link:focus {
  color: var(--color-primary-700);
}

.main-nav-link:hover::after,
.main-nav-link:focus::after {
  background-color: var(--color-secondary-500);
}

.main-nav-link--active {
  color: var(--color-primary-700);
  font-weight: var(--fw-semibold);
}

.main-nav-link--active::after {
  background-color: var(--color-primary-700);
}

.header-cta-wrapper {
  margin-left: var(--space-4);
  flex-shrink: 0;
}

.header-cta {
  font-size: 13px;
}

/* Main content placeholder */

.site-main {
  min-height: 40vh;
  padding: var(--space-6) 0 var(--space-7);
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-800);
  color: var(--color-neutral-0);
  margin-top: auto;
}

.footer-top {
  padding: var(--space-6) 0 var(--space-4);
}

.footer-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: var(--space-5);
}

.footer-column--about {
  max-width: 320px;
}

.footer-heading {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--fw-semibold);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin: 0 0 var(--space-3);
}

.footer-text {
  font-size: var(--fs-small);
  color: rgba(255, 255, 255, 0.9);
}

.footer-text--contact {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.footer-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.14);
  font-size: 12px;
}

.footer-link-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.footer-link {
  font-size: var(--fs-small);
  color: rgba(255, 255, 255, 0.9);
  text-decoration: none;
}

.footer-link:hover,
.footer-link:focus {
  color: var(--color-secondary-300);
}

.footer-bottom {
  border-top: 1px solid rgba(148, 163, 184, 0.5);
  padding: var(--space-3) 0;
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-copy {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.8);
  margin: 0;
}

/* Responsive adjustments */

@media (max-width: 1024px) {
  .header-main-inner {
    flex-wrap: wrap;
    align-items: flex-start;
    padding-top: var(--space-3);
    padding-bottom: var(--space-3);
  }

  .brand {
    flex: 1 0 100%;
  }

  .main-nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .header-cta-wrapper {
    order: -1;
    margin-left: 0;
    margin-bottom: var(--space-2);
  }
}

@media (max-width: 768px) {
  .top-bar-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .top-bar-left {
    flex-wrap: wrap;
    gap: var(--space-2);
  }

  .top-bar-right {
    align-self: flex-end;
  }

  .header-main-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .main-nav {
    width: 100%;
  }

  .main-nav-list {
    flex-wrap: wrap;
    row-gap: var(--space-1);
    column-gap: var(--space-3);
  }

  .site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-6);
  }

  .footer-grid {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 540px) {
  .footer-grid {
    grid-template-columns: 1fr;
  }

  .brand-mark {
    width: 60px;
    height: 60px;
  }

  .brand-title {
    font-size: 18px;
  }
}

/* Optional: dynamic year for environments that may inject JS
   In a static context, the year can be manually updated in HTML. */
